('moon', '', '', '', '', '', '', '', '', '', '', 'Moon', 'moon.jpg', 'moon_thumb.jpg', 'Moon', 'Nikon D50', 'ED127', 'EQ6-Pro', 'None', '1/400sec @ISO 200', 'Donvale', '2009-06-03', 'Waxing Gibbous moon 83.5%. This is the first test shot taken with the ED127 telescope.', 'na', 'None', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'x'),
('ngc0300', '', '', 'NGC 300', '', '', '', '', '', '', 'Sculptor Pinwheel Galaxy', 'NGC 300 Sculptor Pinwheel Galaxy', 'ngc300.jpg', 'ngc300_thumb.jpg', 'Galaxy', 'Nikon D50', 'ED127', 'EQ6-Pro', 'WO Megrez 72FD, PHD, QHY5', '11.5min x 6 (total exposure 69 minutes)', 'Heathcote', '2009-09-18', 'NGC 300 is a bright spiral galaxy in the constellation Sculptor. It is located about 6 million light years from Earth. This image was taken during my first visit to Heathcote. Conditions were good with no wind, moon or clouds to contend with. Although this was my primary target for the night, I ended up not using the RC as I had initially planned, and therefore the image has suffered a from a lack of detail.', 'ngc300_annotated.jpg', 'None', '13.725695062974', '-37.694436361506', '1.690300018110', '0.855897667155', '5136.821755035070', '3404.264236472730', '85.613695917251', '56.737737274546', '88.754323150788', 'y'),
