('ngc2070c', 'Y', '', 'NGC 2070', '', '', '', '', '', '', 'Tarantula Nebula', 'NGC 2070 Tarantula Nebula', 'ngc2070c.jpg', 'ngc2070c_thumb.jpg', 'Nebula', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 10 sec, Bin 2x2', '5 x 20 Mins 1:40 Total', 'Donvale', '2011-08-20', 'Tarantula Nebula (also known as NGC 2070) is an H II star forming region in nearby galaxy The Large Magellanic Cloud. Taken with Ha filter remotely from Hong Kong.', 'ngc2070c_annotated.jpg', '3 KORRW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'f'),
('ngc7099', '', 'M 30', 'NGC 7099', '', '', '', '', '', '', '', 'M30 / NGC 7099', 'ngc7099.jpg', 'ngc7099_thumb.jpg', 'Globular Cluster', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 10 sec, Bin 2x2', 'LRGB 20:10:30:30 total 90 mins', 'Donvale', '2011-08-20', 'M30 is a globular cluster in the constellation Capricornus. Distance from earth is about 28,000 light-years. The bright star is 41 Cap (HIP 107128) Mag 5.2. At the left there is a series of faint galaxies: NGC7103 (the brightest), IC5124, NGC7104, IC1293 and IC5122', 'ngc7099_annotated.jpg', '3 KORRW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'f'),
('ic5358', '', '', '', 'IC 5358', '', '', '', '', '', '', 'IC 5358 Delta Sculptoris', 'ic5358.jpg', 'ic5358_thumb.jpg', 'Cluster', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 10 sec, Bin 2x2', '6 x 10 min L Total 1:00', 'Donvale', '2011-10-19', 'Delta Sculptoris (Mag. +4.59) can be seen in the center of this image. Although its a triple star system, the closest star, Delta Sculptoris B is not visible in this image. However Delta Sculptoris C is clearly visible at the 11 Oclock position with a separation of 74 arcseconds and magnitude of +9.4. Many galaxies are visible in the background including IC5358, IC5353, IC5354, IC5350, IC5349, IC5362 and countless others.', 'ic5358_annotated.jpg', '3 KORRW', '357.230000000000', '-28.130000000000', '1.600000000000', '1.020000000000', '6120.000000000000', '4080.000000000000', '102.000000000000', '68.000000000000', '0.000000000000', 'y'),
('ngc2014', '', '', 'NGC 2014', '', '', '', 'Henize 55', '', '', '', 'NGC 2014 Henize 55', 'ngc2014.jpg', 'ngc2014_thumb.jpg', 'Nebula', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 15 sec, Bin 2x2', 'Ha 4 x 20 min, total 1:20', 'Donvale', '2011-11-08', 'Interesting region in the Large Magellanic Cloud, featuring NGC 2014, NGC 2020, NGC 2032, NGC 2035, NGC 2040, NGC 2029, NGC 1974, NGC 1968', 'ngc2014_annotated.jpg', '3 KORRW', '83.100000000000', '-67.690000000000', '1.600000000000', '1.020000000000', '6120.000000000000', '4080.000000000000', '102.000000000000', '68.000000000000', '0.000000000000', 'y'),
('n70', 'Y', '', '', '', '', '', '', '', '', '', 'N70 Superbubble', 'n70.jpg', 'n70_thumb.jpg', 'Nebula', 'STL-11000M', 'AT12 IN', 'Paramount ME', '20 Sec self guided bin 2x2', '20 min x 4 Ha', 'Donvale', '2011-11-23', 'Henize 70 (also known as N70 and DEM301) is a luminous Superbubble of interstellar gas about 300 light-years in diameter, blown by winds from hot, massive stars and supernova explosions.', 'n70_annotated.jpg', '3 KORRW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'f'),
('ngc1871', '', '', 'NGC 1871', '', '', '', '', '', '', '', 'NGC 1871 LMC Mosaic', 'ngc1871.jpg', 'ngc1871_thumb.jpg', 'Nebula', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 20 sec, Bin 2x2', '2 panel mosaic, 3 Hours total exposure', 'Donvale', '2011-12-02', '2 panel mosaic including NGC 1871', 'ngc1871_annotated.jpg', '3 KORRW', '78.470000000000', '-67.460000000000', '3.210000000000', '1.500000000000', '6120.000000000000', '8160.000000000000', '102.000000000000', '136.000000000000', '0.000000000000', 'y'),
('ngc3576', 'Y', '', 'NGC 3576', '', '', '', '', '', '', '', 'NGC 3576 and NGC 3603', 'ngc3576.jpg', 'ngc3576_thumb.jpg', 'Nebula', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 10 sec, Bin 2x2', 'HaLRGB 120:30:25:20:25 Total 3:40', 'Donvale', '2012-02-17', 'Located at the top of this image, NGC 3576 is an Emission nebula about 9,000 light-years away in the constellation of Carina.  The open cluster NGC 3603 which can be seen in the lower half of the image is much further away at 20,000 light-years. NGC 3603 is a starburst region where extremely rapid star formation takes place. Size:	1.73 x 1.14 deg, Pixel scale: 3.2 arcsec/pixel', 'ngc3576_annotated.jpg', '3 KORRW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'f'),
('ngc6188', 'Y', '', 'NGC 6188', '', '', '', '', '', '', 'Firebird Nebula', 'NGC 6188 Firebird Nebula', 'ngc6188.jpg', 'ngc6188_thumb.jpg', 'Nebula', 'STL-11000M', 'AT8 IN', 'EQ6-Pro', 'Selfguide, 10 sec, Bin 2x2', 'HaLRGB 70:60:50:50:40 total 4:30', 'Glenmaggie', '2011-06-04', 'NGC 6188 is an emission nebula located about 4,000 light years away in the constellation Ara. NGC6164 can be seen at the bottom of the image. Taken at Glenmaggie. Size: 2.24 x 1.49 deg, Pixel scale: 4.02 arcsec/pixel', 'ngc6188_annotated.jpg', 'Paracorr STL', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'f'),
('ngc6188b', '', '', 'NGC 6188', '', '', '', '', '', '', 'Firebird Nebula', 'NGC 6188 Firebird Nebula', 'ngc6188b.jpg', 'ngc6188b_thumb.jpg', 'Nebula', 'STL-11000M', 'AT12 IN', 'Paramount ME', 'Selfguide, 10 sec, Bin 2x2', 'HaLRGB 160:80:80:80:80 Total 8:00', 'Donvale', '2012-04-17', 'NGC 6188 is an emission nebula located about 4,000 light years away in the constellation Ara. Size: 1.77 x 1.16 deg, Pixel scale: 3.21 arcsec/pix', 'ngc6188b_annotated.jpg', '3 KORRW', '250.100000000000', '-48.470000000000', '3.210000000000', '1.020000000000', '6120.000000000000', '4080.000000000000', '102.000000000000', '68.000000000000', '0.000000000000', 'y'),
('rcw058', '', '', '', '', 'RCW 58', '', '', '', '', '', 'RCW 58', 'rcw58.jpg', 'rcw58_thumb.jpg', 'Nebula', 'STL-11000M', 'AT8 IN', 'Paramount ME', 'Selfguide, 10 sec, Bin 2x2', 'HaLRGB 100:20:20:20:20 Total 4:40', 'Donvale', '2011-04-07', 'RCW58 is a Wolf Rayert Bubble formed by wind blown ejecta from a central star.  Part of the dark nebula HMSTG354/DCld292.3-3.7 can be seen at the lower left. Thanks to Steve for the gradient removal :-)', 'na', 'None', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'f'),
